import{_ as a,o,c as r,ag as t}from"./chunks/framework.Lq6hU67C.js";const m=JSON.parse('{"title":"Best practices","description":"","frontmatter":{},"headers":[],"relativePath":"best-practices.md","filePath":"best-practices.md"}'),s={name:"best-practices.md"};function n(l,e,i,c,d,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h1><h2 id="release-every-load-you-own" tabindex="-1">Release every load you own <a class="header-anchor" href="#release-every-load-you-own" aria-label="Permalink to &quot;Release every load you own&quot;">​</a></h2><p>Pair every <code>Load*</code> / <code>Instantiate*</code> / <code>LoadScene*</code> with a matching <code>Release</code> / <code>ReleaseInstance</code> / <code>UnloadSceneAsync</code> on the same handle when the content is no longer needed.</p><p>Prefer <code>OnDestroy</code> or explicit shutdown paths over relying on scene unload.</p><h2 id="scene-transitions" tabindex="-1">Scene transitions <a class="header-anchor" href="#scene-transitions" aria-label="Permalink to &quot;Scene transitions&quot;">​</a></h2><p>Before <code>LoadSceneMode.Single</code>, release handles tied to the outgoing scene. Watch for red <strong>SceneSurvivor</strong> in Live Leaks during level transition testing.</p><h2 id="startup-preloads" tabindex="-1">Startup preloads <a class="header-anchor" href="#startup-preloads" aria-label="Permalink to &quot;Startup preloads&quot;">​</a></h2><p>Long-lived boot assets are valid — mark them with <code>[AddressablesIntentionallyPersistent]</code> so the team knows they are intentional.</p><h2 id="use-instrumented-overloads" tabindex="-1">Use instrumented overloads <a class="header-anchor" href="#use-instrumented-overloads" aria-label="Permalink to &quot;Use instrumented overloads&quot;">​</a></h2><ul><li>Prefer <code>UnloadSceneAsync(AsyncOperationHandle&lt;SceneInstance&gt;)</code> over <code>SceneInstance</code> overload.</li><li>Prefer <code>Addressables.ReleaseInstance</code> over <code>AssetReference.ReleaseInstance(GameObject)</code> for automatic tracking.</li></ul><h2 id="ci-team-workflow" tabindex="-1">CI / team workflow <a class="header-anchor" href="#ci-team-workflow" aria-label="Permalink to &quot;CI / team workflow&quot;">​</a></h2><ul><li>Add a Play Mode test or manual checklist: enter Play, exercise Addressables flows, confirm Live Leaks empty after teardown.</li><li>Run <a href="./how-to/demo-scene.html">demo scene acceptance checklist</a> after package upgrades.</li></ul><h2 id="verbose-mode" tabindex="-1">Verbose mode <a class="header-anchor" href="#verbose-mode" aria-label="Permalink to &quot;Verbose mode&quot;">​</a></h2><p>Enable <strong>Verbose</strong> only when debugging origin confusion — disable for daily profiling.</p><h2 id="assembly-hygiene" tabindex="-1">Assembly hygiene <a class="header-anchor" href="#assembly-hygiene" aria-label="Permalink to &quot;Assembly hygiene&quot;">​</a></h2><p>Exclude only assemblies you truly cannot instrument. Over-excluding hides leaks in gameplay code.</p><h2 id="complement-not-replace-memory-profiler" tabindex="-1">Complement, not replace, Memory Profiler <a class="header-anchor" href="#complement-not-replace-memory-profiler" aria-label="Permalink to &quot;Complement, not replace, Memory Profiler&quot;">​</a></h2><p>Live Leaks shows <strong>missing Release at call sites</strong>. Memory Profiler shows <strong>what</strong> is retained. Use both.</p><h2 id="package-upgrades" tabindex="-1">Package upgrades <a class="header-anchor" href="#package-upgrades" aria-label="Permalink to &quot;Package upgrades&quot;">​</a></h2><p>After upgrading Addressables or this package:</p><ol><li>Re-run <a href="./guide/import-checklist.html">import checklist</a></li><li>Re-run demo acceptance checklist</li><li>Check <a href="./reference/supported-versions.html">Supported versions</a></li></ol>',21)])])}const u=a(s,[["render",n]]);export{m as __pageData,u as default};
